using System.Threading.Channels;

public class EventProcessor : IAsyncDisposable
{
    private readonly Channel<string> _channel = Channel.CreateUnbounded<string>(
        new UnboundedChannelOptions { SingleReader = true });
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        // Task.Run replaces manual Thread creation and is
        // thread-pool-friendly. The async loop replaces
        // ManualResetEvent + lock + Queue entirely.
        _workerTask = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken ct)
    {
        // ReadAllAsync yields items as they arrive and
        // completes when the channel is closed — no manual
        // signal/reset/lock needed.
        await foreach (var item in _channel.Reader.ReadAllAsync(ct))
        {
            Handle(item);
        }
    }

    public void Enqueue(string item)
    {
        if (!_channel.Writer.TryWrite(item))
            throw new InvalidOperationException("Channel is closed.");
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        // Signal the channel as complete — no more writes accepted.
        _channel.Writer.Complete();

        if (_workerTask is null) return;

        // Give the worker time to drain remaining items.
        using var timeoutCts = new CancellationTokenSource(
            timeout ?? TimeSpan.FromSeconds(5));

        try
        {
            await _workerTask.WaitAsync(timeoutCts.Token);
        }
        catch (TimeoutException)
        {
            // Drain timed out — cancel the worker.
            await _cts.CancelAsync();
        }
        catch (OperationCanceledException)
        {
            // Worker was already cancelled — expected.
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    private void Handle(string item)
    {
        // Your processing logic here.
        Console.WriteLine($"Processed: {item}");
    }
}

